@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var file in _files)
        {
            <li class="file-entry @(file.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (file.Error is not null)
                    {
                        <span class="error-message">@file.Info.Name &mdash; @file.Error</span>
                    }
                    else
                    {
                        <span class="file-name">@file.Info.Name</span>
                        <span class="file-size">@FormatSize(file.Info.Size)</span>
                        <span class="file-type">@file.Info.Type</span>
                    }
                </div>
                <button class="remove-btn" @onclick="() => RemoveFile(file)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<DroppedFile> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool isDragOver)
    {
        _isDragOver = isDragOver;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileMetadata[] filesMetadata)
    {
        _isDragOver = false;

        foreach (var meta in filesMetadata)
        {
            var info = new FileInfo(meta.Name, meta.Size, meta.Type);
            string? error = meta.Size > MaxFileSizeBytes
                ? $"File exceeds 10 MB limit ({FormatSize(meta.Size)})"
                : null;
            _files.Add(new DroppedFile(info, error));
        }

        StateHasChanged();
        await NotifyParent();
    }

    private async Task RemoveFile(DroppedFile file)
    {
        _files.Remove(file);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    public record FileInfo(string Name, long Size, string Type);

    private record DroppedFile(FileInfo Info, string? Error);

    public class FileMetadata
    {
        public string Name { get; set; } = "";
        public long Size { get; set; }
        public string Type { get; set; } = "";
    }
}

const dropZoneMap = new WeakMap();

export function initDropZone(element, dotNetRef) {
    const state = { dragCounter: 0 };

    const onDragEnter = (e) => {
        e.preventDefault();
        state.dragCounter++;
        if (state.dragCounter === 1) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', true);
        }
    };

    const onDragOver = (e) => {
        e.preventDefault();
    };

    const onDragLeave = (e) => {
        e.preventDefault();
        state.dragCounter--;
        if (state.dragCounter === 0) {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    };

    const onDrop = (e) => {
        e.preventDefault();
        state.dragCounter = 0;

        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || 'unknown'
        }));

        if (files.length > 0) {
            dotNetRef.invokeMethodAsync('OnFilesDropped', files);
        } else {
            dotNetRef.invokeMethodAsync('OnDragOverChanged', false);
        }
    };

    element.addEventListener('dragenter', onDragEnter);
    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    dropZoneMap.set(element, { onDragEnter, onDragOver, onDragLeave, onDrop });
}

export function dispose(element) {
    const handlers = dropZoneMap.get(element);
    if (handlers) {
        element.removeEventListener('dragenter', handlers.onDragEnter);
        element.removeEventListener('dragover', handlers.onDragOver);
        element.removeEventListener('dragleave', handlers.onDragLeave);
        element.removeEventListener('drop', handlers.onDrop);
        dropZoneMap.delete(element);
    }
}

.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 40px;
    text-align: center;
    color: #6c757d;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 16px;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 8px 12px;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 6px;
    background-color: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    display: flex;
    gap: 16px;
    flex-wrap: wrap;
    align-items: center;
}

.file-name {
    font-weight: 500;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.9em;
}

.error-message {
    color: #dc3545;
    font-weight: 500;
}

.remove-btn {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 4px 10px;
    cursor: pointer;
    font-size: 0.85em;
    transition: background-color 0.15s, color 0.15s;
}

.remove-btn:hover {
    background-color: #dc3545;
    color: #fff;
}

