@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-list">
        @foreach (var file in _files)
        {
            <li class="file-entry @(file.Error is not null ? "file-error" : "")">
                <div class="file-info">
                    @if (file.Error is not null)
                    {
                        <span class="error-message">@file.Info.Name &mdash; @file.Error</span>
                    }
                    else
                    {
                        <span class="file-name">@file.Info.Name</span>
                        <span class="file-size">@FormatSize(file.Info.Size)</span>
                        <span class="file-type">@file.Info.Type</span>
                    }
                </div>
                <button class="remove-btn" @onclick="() => RemoveFile(file)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSizeBytes = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<DroppedFile> _files = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOverChanged(bool isDragOver)
    {
        _isDragOver = isDragOver;
        StateHasChanged();
    }

    [JSInvokable]
    public async Task OnFilesDropped(FileMetadata[] filesMetadata)
    {
        _isDragOver = false;

        foreach (var meta in filesMetadata)
        {
            var info = new FileInfo(meta.Name, meta.Size, meta.Type);
            string? error = meta.Size > MaxFileSizeBytes
                ? $"File exceeds 10 MB limit ({FormatSize(meta.Size)})"
                : null;
            _files.Add(new DroppedFile(info, error));
        }

        StateHasChanged();
        await NotifyParent();
    }

    private async Task RemoveFile(DroppedFile file)
    {
        _files.Remove(file);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _dropZoneRef);
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    public record FileInfo(string Name, long Size, string Type);

    private record DroppedFile(FileInfo Info, string? Error);

    public class FileMetadata
    {
        public string Name { get; set; } = "";
        public long Size { get; set; }
        public string Type { get; set; } = "";
    }
}

